from haystack import Pipeline, component
from typing import Any, Dict, Type

@component
def TypeCheckComponent(@component.output_types(output=Dict[str, Any])):
    def run(input: Dict[str, Any]) -> Dict[str, Any]:
        expected = getattr(self, 'expected_type', dict)
        actual_type = type(input.get('documents', [{}])[0])
        if not issubclass(actual_type, expected):
            raise TypeError(f"Expected {expected.__name__}, got {actual_type.__name__}")
        return {'output': input}
    return run

# Usage in pipeline
pipe = Pipeline()
pipe.add_component("type_check", TypeCheckComponent())
pipe.connect("retriever", "type_check")

