from haystack.components.generators import OpenAIGenerator
import re

def detect_hallucination(generated: str, context_docs: list[str]) -> float:
    context_text = ' '.join([doc.page_content for doc in context_docs])
    # Simple n-gram overlap metric
    gen_words = set(re.findall(r'\w+', generated.lower()))
    ctx_words = set(re.findall(r'\w+', context_text.lower()))
    overlap = len(gen_words.intersection(ctx_words)) / len(gen_words)
    return overlap

# Pipeline integration
@component
def HallucinationCheck(@component.input_types(text=str, context=list)):
    def run(text: str, context: list) -> Dict:
        score = detect_hallucination(text, context)
        if score < 0.4:
            raise ValueError(f"Hallucination detected: {score:.2f} context overlap")
        return {'verified_text': text}

