from haystack.components.builders import PromptBuilder
from haystack.components.retrievers.in_memory import InMemoryEmbeddingRetriever

rerank_prompt = PromptBuilder(template="""Score relevance 1-10:\nQuery: {{query}}\nDoc: {{document}}""")

@component
class AutoReranker:
    def __init__(self):
        self.reranker = OpenAIGenerator()

    @component.input_types(query=str, documents=List[Document])
    @component.output_types(documents=List[Document])
    def run(self, query: str, documents: List[Document]):
        # Rerank only if initial scores low
        if all(score < 0.4 for score in self.initial_scores):
            scored_docs = []
            for doc in documents:
                score_prompt = rerank_prompt.run(query=query, document=doc)
                score = self.reranker.run(**score_prompt)['replies'][0].content
                scored_docs.append((float(score), doc))
            documents = [doc for _, doc in sorted(scored_docs, reverse=True)[:3]]
        return {'documents': documents}

from haystack import component
import logging

@component
class ErrorTrackingComponent:
    def __init__(self):
        self.logger = logging.getLogger(__name__)

    @component.input_types(input=Any)
    @component.output_types(output=Any)
    def run(self, input: Any) -> Dict[str, Any]:
        try:
            # Your component logic
            result = self.process(input)
            return {'output': result}
        except Exception as e:
            self.logger.error(f"Component failed: {str(e)}", exc_info=True)
            # Re-raise to bubble up to Pipeline
            raise RuntimeError(f"Component error: {str(e)}") from e

    def process(self, input):
        # Simulate potential failure
